import pytest
import requests

def test_create_patient_single_char_family_name_boundary(clinician_auth_headers, base_url, unique_identifier):
    payload = {
        "resourceType": "Patient",
        "identifier": [{"system": "urn:test", "value": unique_identifier}],
        "name": [{"family": "A", "given": ["B"]}],
        "gender": "unknown",
        "birthDate": "2000-03-01"
    }
    resp = requests.post(
        f"{base_url}/Patient",
        json=payload,
        headers=clinician_auth_headers
    )
    assert resp.status_code in (201, 422), (
        f"Unexpected status {resp.status_code} at single-char name boundary: {resp.text}"
    )
    if resp.status_code == 201:
        assert resp.json().get("resourceType") == "Patient"
